namespace PortableTestMachine2.Communication;

/// <summary>
/// 장치 통신 공통 인터페이스
/// </summary>
public interface IDeviceService : IDisposable
{
    /// <summary>
    /// 연결 상태
    /// </summary>
    bool IsConnected { get; }

    /// <summary>
    /// 지정 포트로 연결
    /// </summary>
    bool Connect(string portName);

    /// <summary>
    /// 연결 해제
    /// </summary>
    void Disconnect();
}

namespace PortableTestMachine2.Communication;

/// <summary>
/// 전원공급기 SCPI 프로토콜 상수 및 유틸리티
/// </summary>
public static class PowerSupplyProtocol
{
    // 명령어 상수
    public const string INIT_COMMAND = "*ADR 1";
    public const string MEASURE_CURRENT = "MEAS:CURR?";
    public const string SET_VOLTAGE_PREFIX = "SOURS:VOLT ";
    public const string TERMINATOR = "\r\n";

    // 통신 설정
    public const int BAUD_RATE = 9600;
    public const byte RESPONSE_TERMINATOR = 13; // CR
    public const double TIMEOUT_SECONDS = 2.0;

    /// <summary>
    /// 전압 설정 명령 문자열 생성
    /// </summary>
    public static string BuildSetVoltageCommand(double volt)
    {
        return $"{SET_VOLTAGE_PREFIX}{volt}{TERMINATOR}";
    }

    /// <summary>
    /// 전류 응답 문자열 파싱 시도
    /// </summary>
    public static bool TryParseCurrentResponse(string response, out double value)
    {
        return double.TryParse(response.Trim(), out value);
    }
}

namespace PortableTestMachine2.Communication;

/// <summary>
/// IO 보드 프로토콜 상수 및 유틸리티
/// </summary>
public static class IoBoardProtocol
{
    // 통신 설정
    public const int BAUD_RATE = 115200;

    // 프레임 구조
    public const char FRAME_START = 'S';
    public const char FRAME_END = 'E';
    public const int DO_COUNT = 8;

    // DO 인덱스
    public const int CW_INDEX = 0;
    public const int CCW_INDEX = 1;

    /// <summary>
    /// DO 상태 배열로 프레임 문자열 생성 ("S00000000E")
    /// </summary>
    public static string BuildFrame(char[] doState)
    {
        return $"{FRAME_START}{new string(doState)}{FRAME_END}";
    }
}

using System.IO.Ports;
using System.Text;

namespace PortableTestMachine2.Communication;

/// <summary>
/// SCPI 전원공급기 통신 서비스
/// 전류 측정 및 전압 설정을 폴링 방식으로 처리
/// </summary>
public class PowerSupplyService : IDeviceService
{
    private SerialPort? _port;
    private bool _isConnected;
    private readonly StringBuilder _recvBuffer = new();
    private double _currentValue;
    private double _targetVolt;
    private readonly object _lock = new();

    // 요청 단계 폴링 상태
    private int _requestStep;
    private DateTime _stepStartTime;

    /// <summary>
    /// 연결 상태
    /// </summary>
    public bool IsConnected => _isConnected;

    /// <summary>
    /// 측정된 전류값 (스레드 안전)
    /// </summary>
    public double CurrentValue
    {
        get { lock (_lock) return _currentValue; }
        private set { lock (_lock) _currentValue = value; }
    }

    /// <summary>
    /// 목표 전압값 (스레드 안전, 설정 시 전압 명령 전송)
    /// </summary>
    public double TargetVolt
    {
        get { lock (_lock) return _targetVolt; }
        set
        {
            lock (_lock) _targetVolt = value;
            SendSetVoltageCommand(value);
        }
    }

    /// <summary>
    /// 시리얼 포트 연결 및 초기화 명령 전송
    /// </summary>
    public bool Connect(string portName)
    {
        try
        {
            _port = new SerialPort(portName)
            {
                BaudRate = PowerSupplyProtocol.BAUD_RATE,
                DataBits = 8,
                Parity = Parity.None,
                StopBits = StopBits.One,
                Handshake = Handshake.XOnXOff
            };

            _port.DataReceived += Port_DataReceived;
            _port.Open();

            // 초기화 명령 전송
            _port.Write(PowerSupplyProtocol.INIT_COMMAND + PowerSupplyProtocol.TERMINATOR);

            _isConnected = true;
            _requestStep = 0;
            _stepStartTime = DateTime.Now;
            return true;
        }
        catch
        {
            _isConnected = false;
            return false;
        }
    }

    /// <summary>
    /// 연결 해제
    /// </summary>
    public void Disconnect()
    {
        try
        {
            if (_port != null)
            {
                _port.DataReceived -= Port_DataReceived;
                if (_port.IsOpen)
                    _port.Close();
                _port.Dispose();
                _port = null;
            }
        }
        catch
        {
            // 안전한 종료
        }
        finally
        {
            _isConnected = false;
        }
    }

    /// <summary>
    /// 수신 데이터 처리 — CR(13) 수신 시 전류값 파싱
    /// </summary>
    private void Port_DataReceived(object sender, SerialDataReceivedEventArgs e)
    {
        if (_port == null || !_port.IsOpen) return;

        try
        {
            int bytesToRead = _port.BytesToRead;
            byte[] buffer = new byte[bytesToRead];
            _port.Read(buffer, 0, bytesToRead);

            lock (_lock)
            {
                foreach (byte b in buffer)
                {
                    if (b == PowerSupplyProtocol.RESPONSE_TERMINATOR)
                    {
                        // CR 수신 — 버퍼 내용을 전류값으로 파싱
                        string response = _recvBuffer.ToString();
                        _recvBuffer.Clear();

                        if (PowerSupplyProtocol.TryParseCurrentResponse(response, out double value))
                        {
                            _currentValue = value;
                        }

                        // 응답 수신 완료 → 다음 단계로 전환
                        if (_requestStep == 1)
                        {
                            _requestStep = 2;
                            _stepStartTime = DateTime.Now;
                        }
                    }
                    else
                    {
                        _recvBuffer.Append((char)b);
                    }
                }
            }
        }
        catch
        {
            // 수신 오류 무시
        }
    }

    /// <summary>
    /// 전류 측정 요청 명령 전송
    /// </summary>
    public void SendMeasureCurrentCommand()
    {
        if (_port == null || !_port.IsOpen) return;
        _port.Write(PowerSupplyProtocol.MEASURE_CURRENT + PowerSupplyProtocol.TERMINATOR);
    }

    /// <summary>
    /// 전압 설정 명령 전송
    /// </summary>
    public void SendSetVoltageCommand(double volt)
    {
        if (_port == null || !_port.IsOpen) return;
        _port.Write(PowerSupplyProtocol.BuildSetVoltageCommand(volt));
    }

    /// <summary>
    /// 외부 타이머에서 호출 — 요청 단계 폴링 진행
    /// Step 0: 전류 측정 요청 → Step 1
    /// Step 1: 응답 대기 (DataReceived에서 처리) → Step 2
    /// Step 2: 전압 설정 전송 → Step 0
    /// 타임아웃: Step 1이 2초 초과 시 Step 0으로 리셋
    /// </summary>
    public void Poll()
    {
        if (!_isConnected) return;

        lock (_lock)
        {
            switch (_requestStep)
            {
                case 0:
                    // 전류 측정 요청
                    SendMeasureCurrentCommand();
                    _requestStep = 1;
                    _stepStartTime = DateTime.Now;
                    break;

                case 1:
                    // 응답 대기 — 타임아웃 확인
                    double elapsed = (DateTime.Now - _stepStartTime).TotalSeconds;
                    if (elapsed > PowerSupplyProtocol.TIMEOUT_SECONDS)
                    {
                        // 타임아웃 — 초기 단계로 리셋
                        _recvBuffer.Clear();
                        _requestStep = 0;
                    }
                    break;

                case 2:
                    // 전압 설정 전송
                    SendSetVoltageCommand(_targetVolt);
                    _requestStep = 0;
                    _stepStartTime = DateTime.Now;
                    break;
            }
        }
    }

    /// <summary>
    /// 리소스 해제
    /// </summary>
    public void Dispose()
    {
        Disconnect();
        GC.SuppressFinalize(this);
    }
}

using System.IO.Ports;

namespace PortableTestMachine2.Communication;

/// <summary>
/// IO 보드 통신 서비스
/// DO 출력 제어 (CW/CCW 모터 방향 제어)
/// </summary>
public class IoBoardService : IDeviceService
{
    private SerialPort? _port;
    private bool _isConnected;
    private readonly char[] _doState = new char[IoBoardProtocol.DO_COUNT];
    private readonly object _lock = new();

    public IoBoardService()
    {
        // DO 상태 초기화 — 모두 '0'
        Array.Fill(_doState, '0');
    }

    /// <summary>
    /// 연결 상태
    /// </summary>
    public bool IsConnected => _isConnected;

    /// <summary>
    /// 시리얼 포트 연결
    /// </summary>
    public bool Connect(string portName)
    {
        try
        {
            _port = new SerialPort(portName)
            {
                BaudRate = IoBoardProtocol.BAUD_RATE,
                DataBits = 8,
                Parity = Parity.None,
                StopBits = StopBits.One,
                Handshake = Handshake.None
            };

            _port.Open();
            _isConnected = true;
            return true;
        }
        catch
        {
            _isConnected = false;
            return false;
        }
    }

    /// <summary>
    /// 연결 해제
    /// </summary>
    public void Disconnect()
    {
        try
        {
            if (_port != null)
            {
                if (_port.IsOpen)
                    _port.Close();
                _port.Dispose();
                _port = null;
            }
        }
        catch
        {
            // 안전한 종료
        }
        finally
        {
            _isConnected = false;
        }
    }

    /// <summary>
    /// 개별 DO 출력 설정
    /// </summary>
    public void SetDo(int index, char value)
    {
        lock (_lock)
        {
            if (index >= 0 && index < IoBoardProtocol.DO_COUNT)
            {
                _doState[index] = value;
            }
        }
    }

    /// <summary>
    /// 현재 DO 상태로 프레임 문자열 생성
    /// </summary>
    public string GetDoFrame()
    {
        lock (_lock)
        {
            return IoBoardProtocol.BuildFrame(_doState);
        }
    }

    /// <summary>
    /// DO 프레임을 시리얼 포트로 전송
    /// </summary>
    public void SendDoFrame()
    {
        if (_port == null || !_port.IsOpen) return;

        lock (_lock)
        {
            string frame = IoBoardProtocol.BuildFrame(_doState);
            _port.Write(frame);
        }
    }

    /// <summary>
    /// 모터 CW(정회전) — DO[0]=1, DO[1]=0
    /// </summary>
    public void CW()
    {
        lock (_lock)
        {
            _doState[IoBoardProtocol.CW_INDEX] = '1';
            _doState[IoBoardProtocol.CCW_INDEX] = '0';
        }
    }

    /// <summary>
    /// 모터 CCW(역회전) — DO[0]=0, DO[1]=1
    /// </summary>
    public void CCW()
    {
        lock (_lock)
        {
            _doState[IoBoardProtocol.CW_INDEX] = '0';
            _doState[IoBoardProtocol.CCW_INDEX] = '1';
        }
    }

    /// <summary>
    /// 모터 OFF(정지) — DO[0]=0, DO[1]=0
    /// </summary>
    public void OFF()
    {
        lock (_lock)
        {
            _doState[IoBoardProtocol.CW_INDEX] = '0';
            _doState[IoBoardProtocol.CCW_INDEX] = '0';
        }
    }

    /// <summary>
    /// 리소스 해제
    /// </summary>
    public void Dispose()
    {
        Disconnect();
        GC.SuppressFinalize(this);
    }
}
